import os
import boto3
import json
import pickle
import joblib
import torch
import tensorflow as tf
from google.cloud import storage as gcs_storage
from azure.storage.blob import BlobServiceClient
import tempfile
import shutil
from pathlib import Path
import re

class ModelLoader:
    def __init__(self):
        self.model_path = os.getenv('MODEL_PATH', 's3://models/default')
        self.local_cache_dir = tempfile.mkdtemp()
        self.model = None
        
    def parse_cloud_path(self, path):
        if path.startswith('s3://'):
            match = re.match(r's3://([^/]+)/(.+)', path)
            return 's3', match.group(1), match.group(2)
        elif path.startswith('gs://'):
            match = re.match(r'gs://([^/]+)/(.+)', path)
            return 'gcs', match.group(1), match.group(2)
        elif path.startswith('azure://'):
            match = re.match(r'azure://([^/]+)/(.+)', path)
            return 'azure', match.group(1), match.group(2)
        else:
            return 'local', None, path
    
    def get_latest_version_s3(self, bucket_name, prefix):
        s3 = boto3.client('s3')
        response = s3.list_objects_v2(Bucket=bucket_name, Prefix=prefix)
        
        if 'Contents' not in response:
            return None
        
        objects = response['Contents']
        objects.sort(key=lambda x: x['LastModified'], reverse=True)
        return objects[0]['Key']
    
    def get_latest_version_gcs(self, bucket_name, prefix):
        client = gcs_storage.Client()
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=prefix))
        
        if not blobs:
            return None
        
        blobs.sort(key=lambda x: x.updated, reverse=True)
        return blobs[0].name
    
    def get_latest_version_azure(self, container_name, prefix):
        connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        container_client = blob_service_client.get_container_client(container_name)
        
        blobs = list(container_client.list_blobs(name_starts_with=prefix))
        
        if not blobs:
            return None
        
        blobs.sort(key=lambda x: x.last_modified, reverse=True)
        return blobs[0].name
    
    def download_from_s3(self, bucket_name, key):
        s3 = boto3.client('s3')
        local_path = os.path.join(self.local_cache_dir, os.path.basename(key))
        s3.download_file(bucket_name, key, local_path)
        return local_path
    
    def download_from_gcs(self, bucket_name, blob_name):
        client = gcs_storage.Client()
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        local_path = os.path.join(self.local_cache_dir, os.path.basename(blob_name))
        blob.download_to_filename(local_path)
        return local_path
    
    def download_from_azure(self, container_name, blob_name):
        connection_string = os.getenv('AZURE_STORAGE_CONNECTION_STRING')
        blob_service_client = BlobServiceClient.from_connection_string(connection_string)
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        local_path = os.path.join(self.local_cache_dir, os.path.basename(blob_name))
        
        with open(local_path, 'wb') as download_file:
            download_file.write(blob_client.download_blob().readall())
        
        return local_path
    
    def load_model_file(self, file_path):
        ext = Path(file_path).suffix.lower()
        
        if ext == '.pkl':
            with open(file_path, 'rb') as f:
                return pickle.load(f)
        elif ext == '.joblib':
            return joblib.load(file_path)
        elif ext == '.pt' or ext == '.pth':
            return torch.load(file_path)
        elif ext == '.h5':
            return tf.keras.models.load_model(file_path)
        elif ext == '.pb':
            return tf.saved_model.load(file_path)
        else:
            with open(file_path, 'rb') as f:
                return pickle.load(f)
    
    def load_latest_model(self):
        storage_type, bucket_or_container, path = self.parse_cloud_path(self.model_path)
        
        if storage_type == 's3':
            latest_key = self.get_latest_version_s3(bucket_or_container, path)
            if latest_key:
                local_file = self.download_from_s3(bucket_or_container, latest_key)
                self.model = self.load_model_file(local_file)
                print(f"Loaded model from S3: {latest_key}")
        
        elif storage_type == 'gcs':
            latest_blob = self.get_latest_version_gcs(bucket_or_container, path)
            if latest_blob:
                local_file = self.download_from_gcs(bucket_or_container, latest_blob)
                self.model = self.load_model_file(local_file)
                print(f"Loaded model from GCS: {latest_blob}")
        
        elif storage_type == 'azure':
            latest_blob = self.get_latest_version_azure(bucket_or_container, path)
            if latest_blob:
                local_file = self.download_from_azure(bucket_or_container, latest_blob)
                self.model = self.load_model_file(local_file)
                print(f"Loaded model from Azure: {latest_blob}")
        
        elif storage_type == 'local':
            self.model = self.load_model_file(path)
            print(f"Loaded model from local path: {path}")
        
        return self.model
    
    def get_model(self):
        return self.model
    
    def cleanup(self):
        if os.path.exists(self.local_cache_dir):
            shutil.rmtree(self.local_cache_dir)


class InferenceService:
    def __init__(self):
        self.loader = ModelLoader()
        self.model = None
        
    def startup(self):
        print("Starting inference service...")
        print(f"Model path: {self.loader.model_path}")
        self.model = self.loader.load_latest_model()
        print("Model loaded successfully")
        
    def predict(self, input_data):
        if self.model is None:
            raise RuntimeError("Model not loaded")
        
        if hasattr(self.model, 'predict'):
            return self.model.predict(input_data)
        elif callable(self.model):
            return self.model(input_data)
        else:
            raise RuntimeError("Model does not support prediction")
    
    def shutdown(self):
        self.loader.cleanup()
        print("Inference service stopped")


if __name__ == '__main__':
    service = InferenceService()
    service.startup()
    
    import numpy as np
    sample_input = np.array([[1, 2, 3, 4]])
    
    try:
        result = service.predict(sample_input)
        print(f"Prediction result: {result}")
    except Exception as e:
        print(f"Prediction failed: {e}")
    
    service.shutdown()